const MONTHS_RU = ['Январь','Февраль','Март','Апрель','Май','Июнь','Июль','Август','Сентябрь','Октябрь','Ноябрь','Декабрь'];
const DOW_RU = ['Пн','Вт','Ср','Чт','Пт','Сб','Вс'];

/* ---------------- STATE ---------------- */
let state = {
  currentClinic: null,
  currentDoctor: null,
  calYear: 2026, calMonth: 6, // Month is 0-indexed: 6 = July 2026 (matches "current date")
  selectedDate: null,
  selectedTime: null,
  appointments: [],
  history: []
};

/* ---------------- NAVIGATION ---------------- */
function go(screenId, skipHistory){
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  document.getElementById(screenId).classList.add('active');
  const bottomNavScreens = ['screen-map','screen-appointments','screen-profile'];
  document.getElementById('bottom-nav').style.display = bottomNavScreens.includes(screenId) ? 'flex' : 'none';
  if(!skipHistory) state.history.push(screenId);
}
function setNav(which){
  document.querySelectorAll('.nav-item').forEach(n=>n.classList.remove('active'));
  document.getElementById('nav-'+which).classList.add('active');
}

function toast(msg){
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.classList.add('show');
  setTimeout(()=>t.classList.remove('show'), 2000);
}

/* ---------------- LOGIN / REGISTER ---------------- */
function setLoginTab(which){
  document.getElementById('login-tab-phone').classList.toggle('active', which==='phone');
  document.getElementById('login-tab-email').classList.toggle('active', which==='email');
  document.getElementById('login-phone').style.display = which==='phone' ? 'block' : 'none';
  document.getElementById('login-email').style.display = which==='email' ? 'block' : 'none';
}
function doLogin(){
  const phoneVisible = document.getElementById('login-phone').style.display !== 'none';
  const idVal = phoneVisible ? document.getElementById('login-phone').value : document.getElementById('login-email').value;
  const pass = document.getElementById('login-password').value;
  const err = document.getElementById('login-err');
  if(!idVal || !pass){ err.classList.add('show'); return; }
  err.classList.remove('show');
  go('screen-map'); setNav('map'); renderClinics();
}
function doRegister(){
  const fields = ['reg-lastname','reg-firstname','reg-phone','reg-email','reg-password'].map(id=>document.getElementById(id).value);
  const err = document.getElementById('reg-err');
  if(fields.some(v=>!v)){ err.classList.add('show'); return; }
  err.classList.remove('show');
  document.getElementById('profile-name').textContent = fields[1] + ' ' + fields[0];
  document.getElementById('profile-phone').textContent = fields[2];
  document.getElementById('profile-email').textContent = fields[3];
  toast('Регистрация успешна');
  go('screen-map'); setNav('map'); renderClinics();
}
function logout(){
  state.appointments = [];
  go('screen-onboarding');
}

/* ---------------- CLINICS LIST ---------------- */
function renderClinics(){
  const q = (document.getElementById('clinic-search').value || '').toLowerCase();
  const list = document.getElementById('clinics-list');
  const filtered = CLINICS.filter(c => (c.name+' '+c.addr).toLowerCase().includes(q));
  list.innerHTML = filtered.map(c => `
    <div class="clinic-card" onclick="openClinic(${c.id})">
      <img class="clinic-thumb" src="${c.photo}" alt="">
      <div class="clinic-info">
        <div class="name">${c.name}</div>
        <div class="addr">${c.addr.split(',').slice(0,1)[0]}</div>
        <div class="rating-row"><span class="star">★</span> ${c.rating}</div>
      </div>
      <div class="clinic-dist">• ${c.dist}</div>
    </div>
  `).join('');

  // simple map pins
  const mapVisual = document.getElementById('map-pins');
  mapVisual.innerHTML = filtered.map((c,i)=>{
    const positions = [[20,30],[60,20],[75,60],[35,70],[50,45]];
    const [top,left] = positions[i % positions.length];
    return `<div class="map-pin" style="top:${top}%; left:${left}%;" onclick="openClinic(${c.id})" title="${c.name}"></div>`;
  }).join('');
}

function openClinic(id){
  const c = CLINICS.find(cl=>cl.id===id);
  state.currentClinic = c;
  document.getElementById('clinic-photo').src = c.photo;
  document.getElementById('clinic-name').textContent = c.name;
  document.getElementById('clinic-rating').textContent = c.rating;
  document.getElementById('clinic-reviews').textContent = c.reviews;
  document.getElementById('clinic-addr').textContent = c.addr;
  document.getElementById('clinic-hours').textContent = c.hours;
  document.getElementById('clinic-phone').textContent = c.phone;
  document.getElementById('clinic-site').textContent = c.site;
  go('screen-clinic');
}

/* ---------------- DOCTORS ---------------- */
function renderDoctors(){
  const list = document.getElementById('doctors-list');
  list.innerHTML = DOCTORS.map(d => `
    <div class="doctor-card" onclick="openDoctor(${d.id})">
      <img class="doctor-avatar" src="${d.photo}" alt="">
      <div>
        <div class="doctor-name">${d.name}</div>
        <div class="doctor-spec">${d.spec}</div>
        <div class="doctor-meta"><span>${d.exp}</span><span class="star" style="color:#F5A623;">★</span><span>${d.rating}</span></div>
      </div>
      <span class="chev">›</span>
    </div>
  `).join('');
}

function openDoctor(id){
  const d = DOCTORS.find(doc=>doc.id===id);
  state.currentDoctor = d;
  if(!d.available){
    go('screen-noslots');
    return;
  }
  const today = new Date();
  state.calYear = today.getFullYear();
  state.calMonth = today.getMonth();
  state.selectedDate = null;
  renderCalendar();
  go('screen-calendar');
}

/* ---------------- CALENDAR ---------------- */
function renderCalendar(){
  document.getElementById('cal-month-label').textContent = MONTHS_RU[state.calMonth] + ' ' + state.calYear;
  const grid = document.getElementById('cal-grid');
  grid.innerHTML = DOW_RU.map(d=>`<div class="cal-dow">${d}</div>`).join('');

  const firstDay = new Date(state.calYear, state.calMonth, 1);
  let startOffset = firstDay.getDay(); // 0=Sun
  startOffset = (startOffset === 0) ? 6 : startOffset - 1; // convert to Mon-first
  const daysInMonth = new Date(state.calYear, state.calMonth+1, 0).getDate();

  const today = new Date(); today.setHours(0,0,0,0);

  for(let i=0;i<startOffset;i++){ grid.innerHTML += `<div class="cal-day empty"></div>`; }
  for(let day=1; day<=daysInMonth; day++){
    const thisDate = new Date(state.calYear, state.calMonth, day);
    const isPast = thisDate < today;
    const dow = thisDate.getDay();
    const isWeekendUnavailable = (dow===0) && (day % 3 === 0); // sparse mock unavailability
    const disabled = isPast || isWeekendUnavailable;
    const selected = state.selectedDate && state.selectedDate.getTime()===thisDate.getTime();
    grid.innerHTML += `<div class="cal-day ${disabled?'disabled':''} ${selected?'selected':''}" ${disabled?'':`onclick="selectDate(${state.calYear},${state.calMonth},${day})"`}>${day}</div>`;
  }
}
function calShift(dir){
  state.calMonth += dir;
  if(state.calMonth<0){ state.calMonth=11; state.calYear--; }
  if(state.calMonth>11){ state.calMonth=0; state.calYear++; }
  renderCalendar();
}
function selectDate(y,m,d){
  state.selectedDate = new Date(y,m,d);
  renderCalendar();
  setTimeout(()=>{ renderTimes(); go('screen-times'); }, 180);
}

/* ---------------- TIME SLOTS ---------------- */
const TIME_SLOTS = {
  morning:['09:00','09:30','10:00','10:30'],
  day:['12:00','12:30','13:00','13:30','14:00','14:30','15:00','15:30'],
  evening:['16:00','16:30','17:00','17:30','18:00','18:30','19:00']
};
function renderTimes(){
  state.selectedTime = null;
  document.getElementById('btn-book').disabled = true;
  const d = state.selectedDate;
  const label = d.toLocaleDateString('ru-RU', { day:'numeric', month:'long', weekday:'long' });
  document.getElementById('times-date-label').textContent = label;

  const buildGroup = (elId, arr) => {
    document.getElementById(elId).innerHTML = arr.map(t=>
      `<div class="time-slot" onclick="selectTime('${t}', this)">${t}</div>`
    ).join('');
  };
  buildGroup('times-morning', TIME_SLOTS.morning);
  buildGroup('times-day', TIME_SLOTS.day);
  buildGroup('times-evening', TIME_SLOTS.evening);
}
function selectTime(t, el){
  document.querySelectorAll('.time-slot').forEach(s=>s.classList.remove('selected'));
  el.classList.add('selected');
  state.selectedTime = t;
  document.getElementById('btn-book').disabled = false;
}

/* ---------------- CONFIRM BOOKING ---------------- */
function confirmBooking(){
  const c = state.currentClinic, d = state.currentDoctor, date = state.selectedDate, t = state.selectedTime;
  document.getElementById('sum-clinic').textContent = c.name;
  document.getElementById('sum-doctor').textContent = d.name;
  const dateStr = date.toLocaleDateString('ru-RU', { day:'numeric', month:'long', year:'numeric', weekday:'long' });
  document.getElementById('sum-date').textContent = dateStr;
  document.getElementById('sum-time').textContent = t;

  state.appointments.push({
    clinic: c.name, doctor: d.name, doctorShort: shortName(d.name),
    date: date, time: t
  });

  go('screen-confirm');
  renderAppointments();
}
function shortName(full){
  const parts = full.split(' ');
  return parts[0] + ' ' + parts[1][0] + '.';
}

/* ---------------- APPOINTMENTS ---------------- */
function renderAppointments(){
  const list = document.getElementById('appts-list');
  if(state.appointments.length===0){
    list.innerHTML = `<div class="empty-appts">У вас пока нет записей.<br>Нажмите «Записаться», чтобы выбрать клинику.</div>`;
    return;
  }
  list.innerHTML = state.appointments.map(a=>{
    const day = a.date.getDate();
    const mon = a.date.toLocaleDateString('ru-RU',{month:'short'}).replace('.','');
    return `
      <div class="appt-card">
        <div class="appt-date"><div class="num">${day}</div><div class="mon">${mon}</div></div>
        <div style="flex:1;">
          <div class="appt-clinic">${a.clinic}</div>
          <div class="appt-doctor">${a.doctorShort}</div>
          <div class="appt-time">${a.time}</div>
        </div>
        <div class="badge">Предстоящие</div>
      </div>
    `;
  }).join('');
}

/* ---------------- INIT ---------------- */
renderClinics();
renderDoctors();
renderAppointments();
